@dataclass(frozen=True)
class PackageHash:
    """Represents a verified hash for a package distribution."""
    algorithm: str
    digest: str

    def __post_init__(self):
        if self.algorithm not in ALLOWED_HASH_ALGORITHMS:
            raise ValueError(
                f"Hash algorithm '{self.algorithm}' not in allowlist: "
                f"{ALLOWED_HASH_ALGORITHMS}"
            )
        if not SHA256_PATTERN.match(self.digest):
            raise ValueError(f"Invalid {self.algorithm} digest format")

    def __str__(self):
        return f"{self.algorithm}:{self.digest}"


@dataclass
class LockedDependency:
    """Represents a single locked dependency with pinned version and hashes."""
    name: str
    version: str
    hashes: List[PackageHash] = field(default_factory=list)
    index_url: str = "https://pypi.org/simple/"
    is_direct: bool = False
    markers: Optional[str] = None

    def __post_init__(self):
        self.name = self._validate_package_name(self.name)
        self.version = self._validate_version(self.version)
        self._validate_index_url(self.index_url)

    @staticmethod
    def _validate_package_name(name: str) -> str:
        """Validate and normalize package name."""
        if not name or len(name) > MAX_PACKAGE_NAME_LENGTH:
            raise ValueError(
                f"Package name must be 1-{MAX_PACKAGE_NAME_LENGTH} characters"
            )
        # Normalize per PEP 503
        normalized = re.sub(r"[-_.]+", "-", name).lower()
        if not PACKAGE_NAME_PATTERN.match(normalized):
            raise ValueError(
                f"Invalid package name: '{name}' "
                f"(normalized: '{normalized}')"
            )
        return normalized

    @staticmethod
    def _validate_version(version: str) -> str:
        """Validate version string."""
        if not version or len(version) > MAX_VERSION_LENGTH:
            raise ValueError(
                f"Version must be 1-{MAX_VERSION_LENGTH} characters"
            )
        if not VERSION_PATTERN.match(version):
            raise ValueError(f"Invalid version format: '{version}'")
        return version

    @staticmethod
    def _validate_index_url(url: str) -> None:
        """Validate index URL against allowlist."""
        if url not in ALLOWED_INDEX_URLS:
            raise ValueError(
                f"Index URL '{url}' not in allowlist. "
                f"Allowed: {ALLOWED_INDEX_URLS}"
            )

    def to_requirements_line(self) -> str:
        """Generate a requirements.txt line with hashes."""
        line = f"{self.name}=={self.version}"
        if self.markers:
            line += f" ; {self.markers}"
        for h in self.hashes:
            line += f" \\\n    --hash={h}"
        return line


@dataclass
class LockFile:
    """Represents the complete lock file state."""
    dependencies: Dict[str, LockedDependency] = field(default_factory=dict)
    python_version: str = ""
    platform: str = ""
    generated_at: str = ""
    generator_version: str = "1.0.0"
    content_hash: str = ""

    def add_dependency(self, dep: LockedDependency) -> None:
        """Add a validated dependency to the lock file."""
        self.dependencies[dep.name] = dep

    def compute_content_hash(self) -> str:
        """Compute a hash of the lock file contents for integrity verification."""
        hasher = hashlib.sha256()
        for name in sorted(self.dependencies.keys()):
            dep = self.dependencies[name]
            hasher.update(f"{dep.name}=={dep.version}".encode("utf-8"))
            for h in sorted(dep.hashes, key=lambda x: x.digest):
                hasher.update(str(h).encode("utf-8"))
        return hasher.hexdigest()


