class SecureFileOps:
    """Secure file operations with atomic writes and permission management."""

    @staticmethod
    def atomic_write(filepath: Path, content: str, mode: int = LOCK_FILE_MODE) -> None:
        """
        Atomically write content to a file.
        Uses a temporary file + rename to prevent partial writes.
        """
        filepath = Path(filepath).resolve()

        # Validate the target directory exists and is writable
        parent = filepath.parent
        if not parent.is_dir():
            raise FileNotFoundError(f"Directory does not exist: {parent}")

        # Create temp file in the same directory for atomic rename
        fd, tmp_path = tempfile.mkstemp(
            dir=str(parent),
            prefix=f".{filepath.name}.",
            suffix=".tmp",
        )
        try:
            os.fchmod(fd, mode)
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                f.write(content)
            # Atomic rename
            os.replace(tmp_path, str(filepath))
            logger.info(f"Written: {filepath}")
        except Exception:
            # Clean up temp file on failure
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise

    @staticmethod
    def secure_read(filepath: Path) -> str:
        """Read a file with basic security checks."""
        filepath = Path(filepath).resolve()

        if not filepath.is_file():
            raise FileNotFoundError(f"File not found: {filepath}")

        # Check for symlink attacks
        if filepath.is_symlink():
            raise SecurityError(
                f"Refusing to read symlink: {filepath}. "
                f"Use the actual file path."
            )

        return filepath.read_text(encoding="utf-8")


class SecurityError(Exception):
    """Raised when a security check fails."""
    pass


