class InputValidator:
    """Validates all untrusted input before processing."""

    @staticmethod
    def validate_requirements_in(content: str) -> List[str]:
        """
        Parse and validate a requirements.in file.
        Returns a list of validated requirement specifiers.
        """
        valid_requirements = []

        for line_num, raw_line in enumerate(content.splitlines(), 1):
            line = raw_line.strip()

            # Skip empty lines and comments
            if not line or line.startswith("#"):
                continue

            # Skip index URL directives (we enforce our own)
            if line.startswith("-i ") or line.startswith("--index-url"):
                logger.warning(
                    f"Line {line_num}: Ignoring index URL directive "
                    f"(using allowlisted indexes only)"
                )
                continue

            # Skip --extra-index-url (security risk: dependency confusion)
            if line.startswith("--extra-index-url"):
                logger.warning(
                    f"Line {line_num}: Ignoring --extra-index-url "
                    f"(dependency confusion risk)"
                )
                continue

            # Skip -f / --find-links (arbitrary URL risk)
            if line.startswith("-f ") or line.startswith("--find-links"):
                logger.warning(
                    f"Line {line_num}: Ignoring --find-links directive"
                )
                continue

            # Skip -e / --editable (local path risk)
            if line.startswith("-e ") or line.startswith("--editable"):
                logger.warning(
                    f"Line {line_num}: Ignoring editable install "
                    f"(not supported in lock files)"
                )
                continue

            # Validate the requirement specifier
            req = InputValidator._validate_requirement_specifier(line, line_num)
            if req:
                valid_requirements.append(req)

        return valid_requirements

    @staticmethod
    def _validate_requirement_specifier(spec: str, line_num: int) -> Optional[str]:
        """Validate a single requirement specifier."""
        # Split off environment markers
        marker_part = ""
        if ";" in spec:
            spec_part, marker_part = spec.split(";", 1)
            spec = spec_part.strip()
            marker_part = marker_part.strip()

        # Extract package name (before any version specifier)
        match = re.match(
            r"^([A-Za-z0-9]([A-Za-z0-9._-]*[A-Za-z0-9])?)"
            r"(\[([A-Za-z0-9,._-]+)\])?"  # extras
            r"(.*)$",
            spec,
        )
        if not match:
            logger.warning(f"Line {line_num}: Invalid requirement: '{spec}'")
            return None

        pkg_name = match.group(1)
        extras = match.group(3) or ""
        version_spec = match.group(5).strip()

        # Validate package name
        try:
            LockedDependency._validate_package_name(pkg_name)
        except ValueError as e:
            logger.warning(f"Line {line_num}: {e}")
            return None

        # Validate version specifier characters
        allowed_version_chars = set("0123456789.>=<!~,*abcdefghijklmnopqrstuvwxyz ")
        if version_spec and not all(c in allowed_version_chars for c in version_spec.lower()):
            logger.warning(
                f"Line {line_num}: Suspicious version specifier: '{version_spec}'"
            )
            return None

        # Reconstruct validated specifier
        result = f"{pkg_name}{extras}{version_spec}"
        if marker_part:
            result += f" ; {marker_part}"

        return result

    @staticmethod
    def validate_package_name_arg(name: str) -> str:
        """Validate a package name provided as a CLI argument."""
        if not name:
            raise ValueError("Package name cannot be empty")
        try:
            return LockedDependency._validate_package_name(name)
        except ValueError:
            raise ValueError(f"Invalid package name argument: '{name}'")


