class SecurePipRunner:
    """
    Runs pip commands securely with:
    - No shell=True
    - Explicit argument lists
    - Controlled environment variables
    - Index URL enforcement
    """

    def __init__(self, python_executable: Optional[str] = None):
        self.python = python_executable or sys.executable
        self._verify_python_executable()

    def _verify_python_executable(self) -> None:
        """Verify the Python executable exists and is legitimate."""
        python_path = Path(self.python).resolve()
        if not python_path.is_file():
            raise FileNotFoundError(
                f"Python executable not found: {self.python}"
            )

    def _get_secure_env(self) -> Dict[str, str]:
        """
        Create a minimal, secure environment for subprocess execution.
        Strips potentially dangerous environment variables.
        """
        # Start with minimal environment
        secure_env = {}

        # Only pass through necessary variables
        passthrough_vars = [
            "PATH", "HOME", "USER", "LANG", "LC_ALL",
            "SYSTEMROOT", "TEMP", "TMP",  # Windows compatibility
            "SSL_CERT_FILE", "SSL_CERT_DIR",  # TLS certificate locations
            "REQUESTS_CA_BUNDLE", "CURL_CA_BUNDLE",
        ]

        for var in passthrough_vars:
            if var in os.environ:
                secure_env[var] = os.environ[var]

        # Force pip to not use any cached credentials or config
        # that might point to untrusted indexes
        secure_env["PIP_NO_INPUT"] = "1"
        secure_env["PIP_DISABLE_PIP_VERSION_CHECK"] = "1"

        # Prevent pip from using .netrc or keyring for credentials
        # (credentials should be managed through CI/CD secrets, not plaintext)
        secure_env["PIP_NO_CACHE_DIR"] = "1"

        return secure_env

    def _run_pip(self, args: List[str], timeout: int = 300) -> subprocess.CompletedProcess:
        """
        Run a pip command securely.
        Never uses shell=True. Always uses explicit argument lists.
        """
        cmd = [self.python, "-m", "pip"] + args

        logger.info(f"Running: {' '.join(shlex.quote(a) for a in cmd)}")

        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=timeout,
                env=self._get_secure_env(),
                # Never use shell=True
                shell=False,
            )
            return result
        except subprocess.TimeoutExpired:
            raise RuntimeError(
                f"Pip command timed out after {timeout}s: {cmd}"
            )
        except FileNotFoundError:
            raise RuntimeError(
                f"Python executable not found: {self.python}"
            )

    def compile_requirements(
        self,
        requirements_in: Path,
        output_file: Path,
        upgrade: bool = False,
        upgrade_package: Optional[str] = None,
    ) -> str:
        """
        Use pip-compile (from pip-tools) to resolve and lock dependencies.
        Falls back to pip download + hash computation if pip-tools unavailable.
        """
        # First, try pip-compile (preferred)
        args = [
            self.python, "-m", "piptools", "compile",
            "--generate-hashes",
            "--no-header",
            "--no-annotate",
            "--allow-unsafe",
            "--index-url", "https://pypi.org/simple/",
            "--no-emit-index-url",
            "--output-file", str(output_file),
        ]

        if upgrade:
            args.append("--upgrade")

        if upgrade_package:
            validated_name = InputValidator.validate_package_name_arg(upgrade_package)
            args.extend(["--upgrade-package", validated_name])

        args.append(str(requirements_in))

        logger.info(f"Running pip-compile: {' '.join(shlex.quote(a) for a in args)}")

        try:
            result = subprocess.run(
                args,
                capture_output=True,
                text=True,
                timeout=600,
                env=self._get_secure_env(),
                shell=False,
            )

            if result.returncode == 0:
                return SecureFileOps.secure_read(output_file)
            else:
                logger.warning(
                    f"pip-compile failed (exit {result.returncode}): "
                    f"{result.stderr}"
                )
                raise RuntimeError("pip-compile failed")

        except (FileNotFoundError, RuntimeError):
            logger.info(
                "pip-tools not available. Using fallback resolution method."
            )
            return self._fallback_resolve(requirements_in)

    def _fallback_resolve(self, requirements_in: Path) -> str:
        """
        Fallback dependency resolution using pip's own resolver.
        Downloads packages to compute hashes.
        """
        content = SecureFileOps.secure_read(requirements_in)
        requirements = InputValidator.validate_requirements_in(content)

        if not requirements:
            raise ValueError("No valid requirements found")

        with tempfile.TemporaryDirectory(prefix="deplock_") as tmpdir:
            # Use pip download to resolve and download packages
            args = [
                "download",
                "--dest", tmpdir,
                "--no-deps",  # We'll handle deps separately
                "--index-url", "https://pypi.org/simple/",
                "--require-hashes",  # This won't work without hashes, so we skip it for download
            ]

            # First pass: resolve without hashes to get versions
            resolve_args = [
                "download",
                "--dest", tmpdir,
                "--index-url", "https://pypi.org/simple/",
            ] + requirements

            result = self._run_pip(resolve_args, timeout=600)

            if result.returncode != 0:
                raise RuntimeError(
                    f"Dependency resolution failed:\n{result.stderr}"
                )

            # Compute hashes for all downloaded files
            return self._compute_hashes_for_downloads(tmpdir)

    def _compute_hashes_for_downloads(self, download_dir: str) -> str:
        """Compute SHA256 hashes for all downloaded package files."""
        lines = []
        download_path = Path(download_dir)

        for pkg_file in sorted(download_path.iterdir()):
            if not pkg_file.is_file():
                continue

            # Compute SHA256 hash
            sha256_hash = self._compute_file_hash(pkg_file)

            # Parse package name and version from filename
            name, version = self._parse_package_filename(pkg_file.name)
            if name and version:
                lines.append(
                    f"{name}=={version} \\\n"
                    f"    --hash=sha256:{sha256_hash}"
                )

        return "\n".join(lines)

    @staticmethod
    def _compute_file_hash(filepath: Path, algorithm: str = "sha256") -> str:
        """Compute hash of a file securely."""
        if algorithm not in ALLOWED_HASH_ALGORITHMS:
            raise ValueError(f"Algorithm {algorithm} not allowed")

        hasher = hashlib.new(algorithm)
        with open(filepath, "rb") as f:
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                hasher.update(chunk)
        return hasher.hexdigest()

    @staticmethod
    def _parse_package_filename(filename: str) -> Tuple[Optional[str], Optional[str]]:
        """Parse package name and version from a distribution filename."""
        # Handle wheel files: name-version-...whl
        if filename.endswith(".whl"):
            parts = filename.split("-")
            if len(parts) >= 2:
                name = parts[0].replace("_", "-").lower()
                version = parts[1]
                return name, version

        # Handle sdist: name-version.tar.gz or name-version.zip
        for ext in (".tar.gz", ".tar.bz2", ".zip"):
            if filename.endswith(ext):
                base = filename[: -len(ext)]
                # Find the last hyphen that separates name from version
                match = re.match(r"^(.+)-([0-9].*)$", base)
                if match:
                    name = match.group(1).replace("_", "-").lower()
                    version = match.group(2)
                    return name, version

        return None, None

    def install_from_lockfile(self, lockfile_path: Path) -> bool:
        """Install packages from a lock file with hash verification."""
        if not lockfile_path.is_file():
            raise FileNotFoundError(f"Lock file not found: {lockfile_path}")

        args = [
            "install",
            "--require-hashes",
            "--no-deps",
            "--index-url", "https://pypi.org/simple/",
            "--no-cache-dir",
            "-r", str(lockfile_path),
        ]

        result = self._run_pip(args, timeout=600)

        if result.returncode != 0:
            logger.error(f"Installation failed:\n{result.stderr}")
            return False

        logger.info("All packages installed successfully with hash verification")
        return True

    def get_installed_packages(self) -> Dict[str, str]:
        """Get a dict of installed package names to versions."""
        result = self._run_pip(["list", "--format=json"])

        if result.returncode != 0:
            raise RuntimeError(f"Failed to list packages: {result.stderr}")

        packages = {}
        try:
            for pkg in json.loads(result.stdout):
                name = pkg.get("name", "").lower().replace("_", "-")
                version = pkg.get("version", "")
                if name and version:
                    packages[name] = version
        except (json.JSONDecodeError, KeyError) as e:
            raise RuntimeError(f"Failed to parse pip list output: {e}")

        return packages


