class LockFileParser:
    """Parses and generates lock files in requirements.txt format with hashes."""

    @staticmethod
    def parse(content: str) -> LockFile:
        """Parse a lock file from requirements.txt format with hashes."""
        lockfile = LockFile()
        current_line = ""

        for raw_line in content.splitlines():
            line = raw_line.strip()

            # Skip comments and empty lines
            if not line or line.startswith("#"):
                continue

            # Handle line continuations
            if line.endswith("\\"):
                current_line += line[:-1].strip() + " "
                continue
            else:
                current_line += line
                current_line = current_line.strip()

            if not current_line:
                continue

            # Parse the complete requirement line
            dep = LockFileParser._parse_requirement_line(current_line)
            if dep:
                lockfile.add_dependency(dep)

            current_line = ""

        lockfile.content_hash = lockfile.compute_content_hash()
        return lockfile

    @staticmethod
    def _parse_requirement_line(line: str) -> Optional[LockedDependency]:
        """Parse a single requirement line with hashes."""
        # Skip options
        if line.startswith("-"):
            return None

        # Extract hashes
        hashes = []
        hash_pattern = re.compile(r"--hash=(sha256):([a-f0-9]{64})")
        for match in hash_pattern.finditer(line):
            try:
                hashes.append(PackageHash(
                    algorithm=match.group(1),
                    digest=match.group(2),
                ))
            except ValueError as e:
                logger.warning(f"Invalid hash in line: {e}")

        # Remove hash specifications from line
        clean_line = hash_pattern.sub("", line).strip()

        # Extract markers
        markers = None
        if ";" in clean_line:
            clean_line, markers_str = clean_line.split(";", 1)
            markers = markers_str.strip()
            clean_line = clean_line.strip()

        # Parse name==version
        match = re.match(
            r"^([A-Za-z0-9]([A-Za-z0-9._-]*[A-Za-z0-9])?)"
            r"(\[[A-Za-z0-9,._-]+\])?"
            r"==([^\s;]+)",
            clean_line,
        )
        if not match:
            logger.warning(f"Could not parse requirement: '{clean_line}'")
            return None

        name = match.group(1)
        version = match.group(4)

        try:
            return LockedDependency(
                name=name,
                version=version,
                hashes=hashes,
                markers=markers,
            )
        except ValueError as e:
            logger.warning(f"Invalid dependency: {e}")
            return None

    @staticmethod
    def generate(lockfile: LockFile) -> str:
        """Generate lock file content from a LockFile object."""
        lines = [
            "#",
            "# This file is auto-generated by dependency_manager.py",
            "# Do not edit manually. Use 'dependency_manager.py update' instead.",
            "#",
            f"# Content hash: {lockfile.compute_content_hash()}",
            f"# Generated at: {lockfile.generated_at}",
            f"# Python: {lockfile.python_version}",
            f"# Platform: {lockfile.platform}",
            "#",
            "",
        ]

        for name in sorted(lockfile.dependencies.keys()):
            dep = lockfile.dependencies[name]
            lines.append(dep.to_requirements_line())
            lines.append("")

        return "\n".join(lines)


